function _addGateway(address gateway) internal virtual {
    require(_gateways.add(gateway), ERC7786OpenBridgeGatewayAlreadyRegistered(gateway));
    emit GatewayAdded(gateway);
}

function _removeGateway(address gateway) internal virtual {
    require(_gateways.remove(gateway), ERC7786OpenBridgeGatewayNotRegistered(gateway));
    require(_threshold <= _gateways.length(), ERC7786OpenBridgeThresholdViolation());
    emit GatewayRemoved(gateway);
}

function _setThreshold(uint8 newThreshold) internal virtual {
    require(newThreshold > 0 && newThreshold <= _gateways.length(), ERC7786OpenBridgeThresholdViolation());
    _threshold = newThreshold;
    emit ThresholdUpdated(newThreshold);
}

if (_intent.recipientCurrency == NATIVE_CURRENCY) {
    if (_intent.recipientAmount > 0) {
        sendNative(_intent.recipient, _intent.recipientAmount, false);
    }
    if (_intent.feeAmount > 0) {
        sendNative(feeDestinations[_intent.operator], _intent.feeAmount, false);
    }
} else {
    IERC20 requestedCurrency = IERC20(_intent.recipientCurrency);
    if (_intent.recipientAmount > 0) {
        requestedCurrency.safeTransfer(_intent.recipient, _intent.recipientAmount);
    }
    if (_intent.feeAmount > 0) {
        requestedCurrency.safeTransfer(feeDestinations[_intent.operator], _intent.feeAmount);
    }
}

if (src != dst && amount > 0) {
    if (src != address(0)) {
        (uint256 oldWeight, uint256 newWeight) = _writeCheckpoint(_checkpoints[src], subtract, amount);
        emit DelegateVotesChanged(src, oldWeight, newWeight);
    }

    if (dst != address(0)) {
        (uint256 oldWeight, uint256 newWeight) = _writeCheckpoint(_checkpoints[dst], add, amount);
        emit DelegateVotesChanged(dst, oldWeight, newWeight);
    }
}

for (uint256 i = 0; i < _ids.length; ++i) {
    // Cache value to local variable to reduce read costs.
    uint256 id = _ids[i];
    uint256 value = _values[i];

    if (isNonFungible(id)) {
        require(nfOwners[id] == _from);
        nfOwners[id] = _to;
    } else {
        balances[id][_from] = balances[id][_from].sub(value);
        balances[id][_to]   = value.add(balances[id][_to]);
    }
}

if (!isMarketBuy(order.data) && orderInfo.filledAmount >= order.baseTokenAmount) {
    status = uint8(OrderStatus.FULLY_FILLED);
} else if (isMarketBuy(order.data) && orderInfo.filledAmount >= order.quoteTokenAmount) {
    status = uint8(OrderStatus.FULLY_FILLED);
} else if (block.timestamp >= getExpiredAtFromOrderData(order.data)) {
    status = uint8(OrderStatus.EXPIRED);
} else if (cancelled[orderInfo.orderHash]) {
    status = uint8(OrderStatus.CANCELLED);
}

if (collectionType == CollectionType.ERC721) {
    bool isERC721 = IERC165(collection).supportsInterface(ERC721_INTERFACE_ID_1) ||
        IERC165(collection).supportsInterface(ERC721_INTERFACE_ID_2);

    if (!isERC721) {
        return POTENTIAL_INVALID_COLLECTION_TYPE_SHOULD_BE_ERC721;
    }
} else if (collectionType == CollectionType.ERC1155) {
    if (!IERC165(collection).supportsInterface(ERC1155_INTERFACE_ID)) {
        return POTENTIAL_INVALID_COLLECTION_TYPE_SHOULD_BE_ERC1155;
    }
}

if (to == address(DEPLOYER_SYSTEM_CONTRACT) && data.length >= 4) {
    bytes4 selector = bytes4(data[:4]);
    // Check that called function is the deployment method,
    // the others deployer method is not supposed to be called from the default account.
    isSystemCall =
        selector == DEPLOYER_SYSTEM_CONTRACT.create.selector ||
        selector == DEPLOYER_SYSTEM_CONTRACT.create2.selector ||
        selector == DEPLOYER_SYSTEM_CONTRACT.createAccount.selector ||
        selector == DEPLOYER_SYSTEM_CONTRACT.create2Account.selector;
}

if (ERC165Checker.supportsInterface(contractAddress, type(IERC721).interfaceId)) {
    IERC721 erc721 = IERC721(contractAddress);
    erc721.safeTransferFrom(seller, buyer, tokenId);
} else if (ERC165Checker.supportsInterface(contractAddress, type(IERC1155).interfaceId)) {
    IERC1155 erc1155 =IERC1155(contractAddress);
    erc1155.safeTransferFrom(seller, buyer, tokenId, quantity, '');
} else{
    revert("unrecognized token");
}

while (true) {
  uint256 leftChild = i.mul(2).add(1);
  uint256 rightChild = i.mul(2).add(2);
  uint256 maxIndex = i;
  if (leftChild < length && values[keys[leftChild]].gt(values[keys[maxIndex]])) {
    maxIndex = leftChild;
  }
  if (rightChild < length && values[keys[rightChild]].gt(values[keys[maxIndex]])) {
    maxIndex = rightChild;
  }
  if (maxIndex == i) break;
  uint256 tmpKey = keys[i];
  keys[i] = keys[maxIndex];
  keys[maxIndex] = tmpKey;
  i = maxIndex;
}

if (adminSlot == bytes32(0)) {
    string memory upgradeInterfaceVersion = getUpgradeInterfaceVersion(proxy);
    if (upgradeInterfaceVersion.equal("5.0.0") || data.length > 0) {
        IUpgradeableProxy(proxy).upgradeToAndCall(newImpl, data);
    } else {
        IUpgradeableProxy(proxy).upgradeTo(newImpl);
    }
} else {
    address admin = address(uint160(uint256(adminSlot)));
    string memory upgradeInterfaceVersion = getUpgradeInterfaceVersion(admin);
    if (upgradeInterfaceVersion.equal("5.0.0") || data.length > 0) {
        IProxyAdmin(admin).upgradeAndCall(proxy, newImpl, data);
    } else {
        IProxyAdmin(admin).upgrade(proxy, newImpl);
    }
}

if (to.isContract()) {
    try IERC721Receiver(to).onERC721Received(_msgSender(), from, tokenId, _data) returns (bytes4 retval) {
        return retval == IERC721Receiver(to).onERC721Received.selector;
    } catch (bytes memory reason) {
        if (reason.length == 0) {
            revert("ERC721: transfer to non ERC721Receiver implementer");
        } else {
            // solhint-disable-next-line no-inline-assembly
            assembly {
                revert(add(32, reason), mload(reason))
            }
        }
    }
} else {
    return true;
}

if (callData_.length == 68) {
    // ERC20 transfer.
    require(value_ == 0, "MultiTokenPeriodEnforcer:invalid-value-in-erc20-transfer");
    require(bytes4(callData_[0:4]) == IERC20.transfer.selector, "MultiTokenPeriodEnforcer:invalid-method");
    token_ = target_;
    transferAmount_ = uint256(bytes32(callData_[36:68]));
} else if (callData_.length == 0) {
    // Native transfer.
    require(value_ > 0, "MultiTokenPeriodEnforcer:invalid-zero-value-in-native-transfer");
    token_ = address(0);
    transferAmount_ = value_;
} else {
    // If callData length is neither 68 nor 0, revert.
    revert("MultiTokenPeriodEnforcer:invalid-call-data-length");
}

for (uint256 x = 0; x < payoutMembers.length; x++) {
    total += payoutMembers[x].busdValue;
    totalReceived[payoutMembers[x].memberAddress] += payoutMembers[x].busdValue;

    treasury.manage(payoutMembers[x].memberAddress, busdAddress, payoutMembers[x].busdValue * (10 ** 16));

    emit MemberPaid(payoutMembers[x].memberAddress, payoutMembers[x].busdValue);
}

if (from != to && FHE.isInitialized(amount)) {
    if (from != address(0)) {
        store = _delegateCheckpoints[from];
        euint64 newValue = store.latest().sub(amount);
        newValue.allowThis();
        euint64 oldValue = _push(store, newValue);
        emit DelegateVotesChanged(from, oldValue, newValue);
    }
    if (to != address(0)) {
        store = _delegateCheckpoints[to];
        euint64 newValue = store.latest().add(amount);
        newValue.allowThis();
        euint64 oldValue = _push(store, newValue);
        emit DelegateVotesChanged(to, oldValue, newValue);
    }
}

if (method == uint8(SignatureMethod.EthSign)) {
    recovered = ecrecover(
        keccak256(abi.encodePacked("\x19Ethereum Signed Message:\n32", hash)),
        v,
        signature.r,
        signature.s
    );
} else if (method == uint8(SignatureMethod.EIP712)) {
    recovered = ecrecover(hash, v, signature.r, signature.s);
} else {
    revert("INVALID_SIGN_METHOD");
}

if (amountOrId <= minted && amountOrId > 0) {
    address owner = _ownerOf[amountOrId];

    if (msg.sender != owner && !isApprovedForAll[owner][msg.sender]) {
        revert Unauthorized();
    }

    getApproved[amountOrId] = spender;

    emit Approval(owner, spender, amountOrId);
} else {
    allowance[msg.sender][spender] = amountOrId;

    emit Approval(msg.sender, spender, amountOrId);
}

if (usVote.amount == 0) {
    p.userAddrArr.push(_addr);
    uint256 vCount = sqrt(_inAmount);
    p.voteCount = p.voteCount.add(vCount);
    usVote.amount = _inAmount;
    usVote.count = vCount;
} else {
    p.voteCount = p.voteCount.sub(usVote.count);
    //
    uint256 newAmount = usVote.amount.add(_inAmount);
    uint256 newCount = sqrt(newAmount);
    p.voteCount = p.voteCount.add(newCount);
    usVote.amount = newAmount;
    usVote.count = newCount;

}

for (uint256 _poolId = 0; _poolId < _pools.length(); _poolId++) {
  Pool.Data storage _pool = _pools.get(_poolId);

  uint256 _currentRewardWeight = _pool.rewardWeight;
  if (_currentRewardWeight == _rewardWeights[_poolId]) {
    continue;
  }

  // FIXME
  _totalRewardWeight = _totalRewardWeight.sub(_currentRewardWeight).add(_rewardWeights[_poolId]);
  _pool.rewardWeight = _rewardWeights[_poolId];

  emit PoolRewardWeightUpdated(_poolId, _rewardWeights[_poolId]);
}

if (config.validatorType == DAValidatorType.Rollup) {
    bytecode = ContractsBytecodesLib.getCreationCode("RollupL2DAValidator");
} else if (config.validatorType == DAValidatorType.NoDA) {
    bytecode = ContractsBytecodesLib.getCreationCode("ValidiumL2DAValidator");
} else if (config.validatorType == DAValidatorType.Avail) {
    bytecode = ContractsBytecodesLib.getCreationCode("AvailL2DAValidator");
} else {
    revert("Invalid DA validator type");
}

for (uint256 i = 0; i < partsLength; ++i) {
    bytes memory part = bytes(parts[i]);
    bytes memory extractedSelector = new bytes(10);
    // Selector length 10 is 0x + 4 bytes
    for (uint256 j = 0; j < 10; ++j) {
        extractedSelector[j] = part[j];
    }
    bytes4 selector = bytes4(vm.parseBytes(string(extractedSelector)));
    selectors[i] = selector;
}

for (uint256 i = 0; i < 8; i++) {
    bytes32 safeDigest;
    {
        bytes32 guardiansDigest = EIP712Utils.buildDigest(
            _emergencyUpgradeBoardDigest,
            keccak256(abi.encode(EXECUTE_EMERGENCY_UPGRADE_GUARDIANS_TYPEHASH, _upgradeId))
        );
        safeDigest = ISafe(guardiansMembers[i]).getMessageHash(abi.encode(guardiansDigest));
    }

    (uint8 v, bytes32 r, bytes32 s) = vm.sign(_governorWallet, safeDigest);
    guardiansRawSignatures[i] = abi.encodePacked(r, s, v);
}

for (uint256 i = 0; i < signatureCount_; ++i) {
    bytes memory signature_ = _signatures[i * SIGNATURE_LENGTH:(i + 1) * SIGNATURE_LENGTH];

    currentOwner_ = ECDSA.recover(_hash, signature_);

    if (currentOwner_ <= lastOwner_ || !s_.isSigner[currentOwner_]) return ERC1271Lib.SIG_VALIDATION_FAILED;

    validSignatureCount_++;

    if (validSignatureCount_ >= threshold_) {
        return ERC1271Lib.EIP1271_MAGIC_VALUE;
    }

    lastOwner_ = currentOwner_;
}

requestId = s_vrfCoordinator.requestRandomWords(
    VRFV2PlusClient.RandomWordsRequest({
        keyHash: keyHash,
        subId: s_subscriptionId,
        requestConfirmations: requestConfirmations,
        callbackGasLimit: callbackGasLimit,
        numWords: numWords,
        extraArgs: VRFV2PlusClient._argsToBytes(VRFV2PlusClient.ExtraArgsV1({nativePayment: enableNativePayment}))
    })
);

for (uint256 i = 0; i < numberOfMessages; ++i) {
    uint32 currentMessageLength = uint32(bytes4(_totalL2ToL1PubdataAndStateDiffs[calldataPtr:calldataPtr + 4]));
    calldataPtr += 4;
    bytes32 hashedMessage = EfficientCall.keccak(
        _totalL2ToL1PubdataAndStateDiffs[calldataPtr:calldataPtr + currentMessageLength]
    );
    calldataPtr += currentMessageLength;
    reconstructedChainedMessagesHash = keccak256(abi.encode(reconstructedChainedMessagesHash, hashedMessage));
}

for (uint256 i = 0; i < numberOfBytecodes; ++i) {
    uint32 currentBytecodeLength = uint32(
        bytes4(_totalL2ToL1PubdataAndStateDiffs[calldataPtr:calldataPtr + 4])
    );
    calldataPtr += 4;
    reconstructedChainedL1BytecodesRevealDataHash = keccak256(
        abi.encode(
            reconstructedChainedL1BytecodesRevealDataHash,
            L2ContractHelper.hashL2BytecodeCalldata(
                _totalL2ToL1PubdataAndStateDiffs[calldataPtr:calldataPtr + currentBytecodeLength]
            )
        )
    );
    calldataPtr += currentBytecodeLength;
}

for (uint256 i = 0; i < numberOfL2ToL1Logs; ++i) {
    bytes32 hashedLog = EfficientCall.keccak(
        _operatorInput[calldataPtr:calldataPtr + L2_TO_L1_LOG_SERIALIZE_SIZE]
    );
    calldataPtr += L2_TO_L1_LOG_SERIALIZE_SIZE;
    l2ToL1LogsTreeArray[i] = hashedLog;
    reconstructedChainedLogsHash = keccak256(abi.encode(reconstructedChainedLogsHash, hashedLog));
}

if (
    executions_[1].target != terms_.tokenAddress || executions_[1].value != 0 || executions_[1].callData.length != 68
        || bytes4(executions_[1].callData[0:4]) != IERC20.transfer.selector
        || address(uint160(uint256(bytes32(executions_[1].callData[4:36])))) != terms_.recipient
        || uint256(bytes32(executions_[1].callData[36:68])) != terms_.amount
) {
    revert("SpecificActionERC20TransferBatchEnforcer:invalid-second-transaction");
}

if (feeAmount > 0) {
    // Mint ERC-6909 tokens for unspecified currency fee and call handler
    unspecified.take(poolManager, address(this), feeAmount.toUint128(), true);
    _afterSwapHandler(key, params, delta, targetUnspecifiedAmount, feeAmount);

    // Emit the swap event with the amounts ordered correctly
    if (unspecified == key.currency0) {
        emit HookFee(PoolId.unwrap(key.toId()), sender, feeAmount.toUint128(), 0);
    } else {
        emit HookFee(PoolId.unwrap(key.toId()), sender, 0, feeAmount.toUint128());
    }
}

try IERC7984ERC20Wrapper(fromToken()).finalizeUnwrap(unwrapRequestId_, unwrapAmountCleartext, decryptionProof) {
    // No need to validate input since `finalizeUnwrap` request succeeded
} catch {
    // Must validate input since `finalizeUnwrap` request failed
    bytes32[] memory handles = new bytes32[](1);
    handles[0] = euint64.unwrap(fromToken().unwrapAmount(unwrapRequestId_));
    FHE.checkSignatures(handles, abi.encode(unwrapAmountCleartext), decryptionProof);
}

if (defenderOpts.skipVerifySourceCode) {
    inputBuilder[i++] = "--verifySourceCode";
    inputBuilder[i++] = "false";
} else if (bytes(defenderOpts.licenseType).length != 0) {
    inputBuilder[i++] = "--licenseType";
    inputBuilder[i++] = string(abi.encodePacked('"', defenderOpts.licenseType, '"'));
} else if (!defenderOpts.skipLicenseType && bytes(contractInfo.license).length != 0) {
    inputBuilder[i++] = "--licenseType";
    inputBuilder[i++] = string(abi.encodePacked('"', _toLicenseType(contractInfo), '"'));
}

if (
            !((orders[orderSigned.user][hash] ||
                ecrecover(
                    keccak256(
                        abi.encodePacked("\x19Ethereum Signed Message:\n32", hash)
                    ),
                    orderSigned.v,
                    orderSigned.r,
                    orderSigned.s
                ) ==
                orderSigned.user) && block.number <= orderSigned.expires)
        ) return 0;

if (_protocolFee > 0) {
    feesToProtocol0 = feesToVault0.mul(_protocolFee).div(1e6);
    feesToProtocol1 = feesToVault1.mul(_protocolFee).div(1e6);
    feesToVault0 = feesToVault0.sub(feesToProtocol0);
    feesToVault1 = feesToVault1.sub(feesToProtocol1);
    accruedProtocolFees0 = accruedProtocolFees0.add(feesToProtocol0);
    accruedProtocolFees1 = accruedProtocolFees1.add(feesToProtocol1);
}

ProposedUpgrade memory proposedUpgrade = ProposedUpgrade({
    l2ProtocolUpgradeTx: l2ProtocolUpgradeTx,
    bootloaderHash: bytes32(0),
    defaultAccountHash: bytes32(0),
    evmEmulatorHash: bytes32(0),
    verifier: address(0),
    verifierParams: VerifierParams({
        recursionNodeLevelVkHash: bytes32(0),
        recursionLeafLevelVkHash: bytes32(0),
        recursionCircuitsSetVksHash: bytes32(0)
    }),
    l1ContractsUpgradeCalldata: new bytes(0),
    postUpgradeCalldata: new bytes(0),
    upgradeTimestamp: 0,
    newProtocolVersion: _protocolVersion
});

deployed.multicall3 = Utils.deployThroughL1({
    bytecode: ContractsBytecodesLib.getCreationCode("Multicall3"),
    constructorargs: constructorData,
    create2salt: "",
    l2GasLimit: Utils.MAX_PRIORITY_TX_GAS,
    factoryDeps: new bytes[](0),
    chainId: config.chainId,
    bridgehubAddress: config.bridgehubAddress,
    l1SharedBridgeProxy: config.l1SharedBridgeProxy
});

address l2ChainAdminAddress = Utils.deployThroughL1({
    bytecode: ContractsBytecodesLib.readChainAdminBytecode(),
    constructorargs: abi.encode(new address[](0)),
    create2salt: bytes32(0),
    l2GasLimit: Utils.MAX_PRIORITY_TX_GAS,
    factoryDeps: new bytes[](0),
    chainId: config.gatewayChainId,
    bridgehubAddress: config.bridgehub,
    l1SharedBridgeProxy: config.sharedBridgeProxy
});

if (ADDRESS_ONE != baseTokenAddress) {
    console.log("Base token not ETH, approving");
    IERC20 baseToken = IERC20(baseTokenAddress);

    bytes memory approvalCalldata = abi.encodeCall(baseToken.approve, (l1SharedBridgeProxy, amountToApprove));

    calls = new Call[](1);
    calls[0] = Call({target: baseTokenAddress, value: 0, data: approvalCalldata});

    ethAmountToPass = 0;
} else {
    console.log("Base token is ETH, no need to approve");
    ethAmountToPass = amountToApprove;
}

for (uint256 i = 0; i < securityCouncilMembers.length; i++) {
    bytes32 safeDigest;
    {
        bytes32 securityCouncilDigest = EIP712Utils.buildDigest(
            _emergencyUpgradeBoardDigest,
            keccak256(abi.encode(EXECUTE_EMERGENCY_UPGRADE_SECURITY_COUNCIL_TYPEHASH, _upgradeId))
        );
        safeDigest = ISafe(securityCouncilMembers[i]).getMessageHash(abi.encode(securityCouncilDigest));
    }
    {
        (uint8 v, bytes32 r, bytes32 s) = vm.sign(_governorWallet, safeDigest);
        securityCouncilRawSignatures[i] = abi.encodePacked(r, s, v);
    }
}

for (uint256 i = 0; i < securityCouncilMembers.length; i++) {
    bytes32 safeDigest;
    {
        bytes32 digest = EIP712Utils.buildDigest(
            securityCouncilDigest,
            keccak256(abi.encode(APPROVE_UPGRADE_SECURITY_COUNCIL_TYPEHASH, upgradeId))
        );
        safeDigest = ISafe(securityCouncilMembers[i]).getMessageHash(abi.encode(digest));
    }
    {
        (uint8 v, bytes32 r, bytes32 s) = vm.sign(_governorWallet, safeDigest);
        securityCouncilRawSignatures[i] = abi.encodePacked(r, s, v);
    }
}

forceDeployments[4] = ForceDeployment({
    bytecodeHash: fixedForceDeploymentsData.chainAssetHandlerBytecodeHash,
    newAddress: address(L2_CHAIN_ASSET_HANDLER),
    callConstructor: true,
    value: 0,
    // solhint-disable-next-line func-named-parameters
    input: abi.encode(
        fixedForceDeploymentsData.l1ChainId,
        fixedForceDeploymentsData.aliasedL1Governance,
        address(L2_BRIDGE_HUB),
        address(L2_ASSET_ROUTER),
        address(L2_MESSAGE_ROOT)
    )
});

for (uint256 i = 0; i < aggregatorsLength_; ++i) {
    bytes32 aggregatorIdHash_ = keccak256(abi.encode(_aggregatorIds[i]));
    bool status_ = _statuses[i];
    if (isAggregatorAllowed[aggregatorIdHash_] != status_) {
        isAggregatorAllowed[aggregatorIdHash_] = status_;

        emit ChangedAggregatorIdStatus(aggregatorIdHash_, _aggregatorIds[i], status_);
    }
}
